  // Структура: см. src/lib/kp/types.ts (KpConfig)\n  kpConfig      Json?\n  // Слоган/девиз бренда для обложки и футера PDF\n  tagline       String?\n  // Фирменное фото-фон обложки (опционально, перебивает 3D-превью в некоторых темах)\n  coverPhotoUrl String?\n\n  prices           MasterPrice[]\n  priceVariants    PriceVariant[]\n  estimates        Estimate[]\n  sessions         Session[]\n  bridgeTokens     BridgeToken[]\n  chatSessions     ChatSession[]\n  customItems      CustomItem[]\n  portfolioWorks   PortfolioWork[]\n  reviews          MasterReview[]\n  kpBrief          MasterBrief?\n  measurements     MeasurementObject[]\n  instagramAccount InstagramAccount?\n  instagramSession InstagramSession?\n  clients          Client[]\n  objectPhotos     ObjectPhoto[]\n\n  // Portfolio\n  portfolioSlug String? @unique // e.g. \"ivan-almaty\" → potolok.ai/master/ivan-almaty\n  portfolioBio  String? // Краткое описание мастера для публичной страницы\n\n  rangefinders    Rangefinder[]\n  pendingPayments PendingPayment[]\n}\n\nmodel Session {\n  id        String   @id @default(uuid())\n  masterId  String\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  master Master @relation(fields: [masterId], references: [id], onDelete: Cascade)\n}\n\n// Single-use, short-lived (≤60s) handoff token used by the mobile app to\n// open a web view as the same master without putting the long-lived\n// session_token into the URL (which would leak via logs, history, Referer).\nmodel BridgeToken {\n  id        String   @id @default(uuid())\n  masterId  String\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  master Master @relation(fields: [masterId], references: [id], onDelete: Cascade)\n\n  @@index([expiresAt])\n}\n\nenum SubscriptionTier {\n  FREE\n  PRO\n  PROPLUS\n}\n\n// ============================================\n// PRICING\n// ============================================\n\nmodel MasterPrice {\n  id             String  @id @default(uuid())\n  masterId       String\n  itemCode       String // код из PRODUCT_ITEMS (canvas_320, spot_gu10, ...)\n  price          Float\n  // Цена работы монтажнику. null = используется default (30% от price).\n  // Мастер выставляет вручную в Прайсе или в форме КП (Нариман 2026-05-31).\n  installerPrice Float?\n  photoUrl       String? // фото к дефолтной позиции (опционально)\n  isHidden       Boolean @default(false) // мастер скрыл позицию — не показывать в прайсе и КП\n\n  master Master @relation(fields: [masterId], references: [id], onDelete: Cascade)\n\n  @@unique([masterId, itemCode])\n}\n\n// ============================================\n// CUSTOM ITEMS (per-master custom price positions)\n// ============================================\n\nmodel CustomItem {\n  id       String @id @default(uuid())\n  masterId String\n  code     String\n  name     String\n  unit     String // \"м²\" | \"м.п.\" | \"шт.\"\n  price    Float\n  category String @default(\"custom\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  master Master @relation(fields: [masterId], references: [id], onDelete: Cascade)\n\n  @@unique([masterId, code])\n}\n\n// ============================================\n// PRICE VARIANTS (варианты с фото — мастер сам создаёт)\n// ============================================\n// Под каждой категорией (полотно, профиль, софит, ...) мастер может создать\n// свои варианты с фото. Например, под \"canvas\" → \"Pongs белый матовый 2500₸ + фото\".\n// В КП каждая строка может быть привязана к конкретному variantId — если в категории\n// 2+ вариантов, строка тапается и открывается picker.\n\nmodel PriceVariant {\n  id             String  @id @default(uuid())\n  masterId       String\n  category       String // canvas | profile | spot | chandelier | curtain | gardina | podshtornik | track | lightline\n  baseCode       String? // опционально: маппинг на код из PRODUCT_ITEMS (canvas_320, profile_shadow, ...) — null = полностью своя позиция\n  name           String\n  unit           String\n  price          Float\n  // Цена работы монтажнику (Нариман 2026-05-31). null = default 30% от price.\n  installerPrice Float?\n  photoUrl       String? // Vercel Blob URL\n  noInsert       Boolean @default(false) // флаг «вариант профиля без вставки» (теневые/парящие)\n  sortOrder      Int     @default(0)\n\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  // Soft-delete (см. /dashboard/trash). null = живая запись.\n  deletedAt DateTime?\n\n  master Master @relation(fields: [masterId], references: [id], onDelete: Cascade)\n\n  @@index([masterId, category])\n  @@index([masterId, deletedAt])\n}\n\n// ============================================\n// ESTIMATES\n// ============================================\n\nmodel Estimate {\n  id       String @id @default(uuid())\n  publicId String @unique @default(uuid())\n  masterId String\n\n  // Client info (legacy + new CRM link)\n  clientName    String?\n  clientPhone   String?\n  clientAddress String?\n  clientId      String?\n  client        Client? @relation(fields: [clientId], references: [id], onDelete: SetNull)\n\n  // Электронный договор\n  contractPublicId        String?   @unique\n  contractTextSnapshot    Json?\n  contractCreatedAt       DateTime?\n  contractSignedAt        DateTime?\n  contractSignerName      String?\n  contractSignerPassport  String?\n  contractSignerIp        String?\n  contractSignerUserAgent String?\n  // Условия договора (даты + схема оплаты)\n  workStartDate           DateTime?\n  workDurationDays        Int?\n  paymentSchedule         Json? // [{ name: string, percent: number, when: string }]\n\n  // Электронный Акт выполненных работ\n  actPublicId        String?   @unique\n  actCreatedAt       DateTime?\n  actSignedAt        DateTime?\n  actSignerName      String?\n  actSignerIp        String?\n  actSignerUserAgent String?\n  actCompletionDate  DateTime? // когда работы факт